uniform vec2 u_resolution;
varying vec2 v_uv;

void main()
{
    vec3 color;
    float t = dot(texture2D(u_texture, v_uv).rgb, vec3(0.2126, 0.7152, 0.0722));

    if (t < 0.25)
        color = mix(vec3(0.0, 0.0, 0.0), vec3(0.0, 0.0, 0.6), t / 0.25);
    else if (t < 0.5)
        color = mix(vec3(0.0, 0.0, 0.6), vec3(0.5, 0.0, 0.6), (t - 0.25) / 0.25);
    else if (t < 0.75)
        color = mix(vec3(0.5, 0.0, 0.6), vec3(0.95, 0.1, 0.05), (t - 0.5) / 0.25);
    else
        color = mix(vec3(0.95, 0.1, 0.05), vec3(1.0, 1.0, 0.2), (t - 0.75) / 0.25);

    gl_FragColor = vec4(clamp(color, 0.0, 1.0), 1.0);
}

